SELECT MAX(graduation_rate) AS max_graduation_rate
FROM high_school_graduation_statistics
WHERE ethnicity_id = 1 AND year = 2023;

SELECT SUM(total_graduated) AS total_students_graduated
FROM high_school_graduation_statistics
WHERE year = 2023;

SELECT total_graduated
FROM high_school_graduation_statistics
WHERE year = 2023;

SELECT SUM(total_enrolled) AS total_students_enrolled
FROM college_enrollment_statistics
WHERE year = 2023 AND ethnicity_id = 1;

SELECT total_enrolled, college_name, program_of_study
FROM college_enrollment_statistics
WHERE year = 2023;

SELECT ethnicity_name
FROM ethnicities
WHERE population_percentage = (
  SELECT MAX(population_percentage)
  FROM ethnicities
);

SELECT ethnicity, AVG(graduated_high_school) AS avg_graduated_high_school
FROM student_demographics
GROUP BY ethnicity;

SELECT ethnicity_id, program_id, participants
FROM program_participation
WHERE year = 2023;

SELECT SUM(participants) AS total_participants
FROM program_participation
WHERE program_id = 0 AND year = 2023;
